SELECT failureCATEGORY, COUNT(*) AS failure_count
FROM test_failures
GROUP BY failureCATEGORY;

SELECT package_name, version, MAX(updated_date) AS latest_update
FROM software_packages
GROUP BY package_name;

SELECT developer_id, COUNT(*) as assignment_count
FROM test_assignments
GROUP BY developer_id;

SELECT COUNT(*) 
FROM test_assignments 
WHERE status = 'completed';

SELECT COUNT(*) AS total_test_failures
FROM test_failures
WHERE failureCATEGORY = 'assertion';
